struct Node {
    int data;
    struct Node* next;
};

struct Node* head = NULL;

// Delete first node
void deleteAtBeginning() {
    if (head == NULL) {
        printf("List is empty\n");
        return;
    }

    struct Node* temp = head;

    // If only one node
    if (head->next == head) {
        head = NULL;
        free(temp);
        return;
    }

    struct Node* last = head;
    while (last->next != head)
        last = last->next;

    head = head->next;
    last->next = head;
    free(temp);
}

// Delete last node
void deleteAtEnd() {
    if (head == NULL) {
        printf("List is empty\n");
        return;
    }

    // Only one node
    if (head->next == head) {
        free(head);
        head = NULL;
        return;
    }

    struct Node* temp = head;
    struct Node* prev = NULL;

    while (temp->next != head) {
        prev = temp;
        temp = temp->next;
    }

    prev->next = head;
    free(temp);
}

// Delete node with given value
void deleteByValue(int key) {
    if (head == NULL) {
        printf("List is empty\n");
        return;
    }

    struct Node *curr = head, *prev = NULL;

    // If head needs to be deleted
    if (curr->data == key) {
        deleteAtBeginning();
        return;
    }

    do {
        prev = curr;
        curr = curr->next;

        if (curr->data == key) {
            prev->next = curr->next;
            free(curr);
            return;
        }

    } while (curr != head);

    printf("Value not found\n");
}

