}

void insert(int pos, int value) {
    struct node *p, *t;

    p = (struct node*)malloc(sizeof(struct node));
    p->data = value;
    p->next = NULL;

    // Edge case: insert at beginning
    if (pos == 0) {
        if (first == NULL) {
            first = last = p;
        } else {
            p->next = first;
            first = p;
        }
    }
    else {
        t = first;

        // Traverse to (pos-1)th node
        for (int i = 1; i < pos - 1; i++) {
            t = t->next;
        }

        p->next = t->next;
        t->next = p;
    }
}

#include <stdio.h>
#define MAX 5

int queue[MAX];
int front = -1, rear = -1;

// Insertion (Enqueue) - Array based Queue
void insert(int value) {
    if (rear == MAX - 1) {
        printf("Queue Overflow\n");
        return;
    }

    if (front == -1)
        front = 0;

    rear = rear + 1;
    queue[rear] = value;
}

int main() {
    insert(10);
    insert(20);
    insert(30);
    return 0;
}

void display() {
    for (int i = front; i <= rear; i++) {
        printf("%d ", queue[i]);
    }
}

